import sys
import math

def main():
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    D = float(data[1])

    coords = []
    for i in range(N):
        x = int(data[2 + 2 * i])
        y = int(data[3 + 2 * i])
        coords.append((x, y))

    # Initialize infected status
    infected = [False] * N
    infected[0] = True  # Person 1 is infected initially

    # Brute-force approach: check pairwise distances between all infected and uninfected people
    for _ in range(N):
        changed = False
        for i in range(N):
            if infected[i]:
                for j in range(N):
                    if not infected[j]:
                        dx = coords[i][0] - coords[j][0]
                        dy = coords[i][1] - coords[j][1]
                        dist = math.sqrt(dx * dx + dy * dy)
                        if dist <= D:
                            infected[j] = True
                            changed = True
        if not changed:
            break  # No more infections possible

    for status in infected:
        print("Yes" if status else "No")

if __name__ == "__main__":
    main()
